import React from 'react';
import { Pagination, Dropdown, Menu, Space, Button } from 'antd';
import '../../../CSS/CustomPagination.css';
import { PAGE_SIZE  } from '../../../utils/constants'
import { DownOutlined } from '@ant-design/icons';
const CustomPagination = (props) => {
    
    const menu = (<Menu
        items={[
        {
            label: <a onClick = {()=>props.handlePgaeSizeChange(PAGE_SIZE.PAGE_10)} >{PAGE_SIZE.PAGE_10}</a>,
            key: '0',
        },
        {
            label: <a onClick = {()=>props.handlePgaeSizeChange(PAGE_SIZE.PAGE_20)} >{PAGE_SIZE.PAGE_20}</a>,
            key: '1',
        },        
        {
            label: <a onClick = {()=>props.handlePgaeSizeChange(PAGE_SIZE.PAGE_50)} >{PAGE_SIZE.PAGE_50}</a>,
            key: '2',
        },        
        {
            label: <a onClick = {()=>props.handlePgaeSizeChange(PAGE_SIZE.PAGE_100)} >{PAGE_SIZE.PAGE_100}</a>,
            key: '2',
        },
        ]}
    />);

    return (
        <div className="pagination_row">
            <div className='font-family-weight-400 font-s14 font-h22' style = {{display: 'contents', color: '#212121'}}>{ props.paginationDetails.totalElements > 0 ? props.pageDetail.pageSize * props.pageDetail.current + 1 : props.paginationDetails.totalElements } to {  props.pageDetail.pageSize * props.pageDetail.current + props.paginationDetails.numberOfElements } of { props.paginationDetails.totalElements }</div>
            <Dropdown  overlay={menu} trigger={['click']}>
                <Button style = {{  marginLeft: '16px', color: '#212121'}}>
                    <Space>
                        {props.curentPageOption}
                        <DownOutlined />
                    </Space>
                </Button>
            </Dropdown>
            <Pagination
                className="pagination_style"
                current={props.pageDetail.current+1}
                pageSize={props.pageDetail.pageSize}
                total={props.paginationDetails.totalElements}
                onChange={props.handlePageChange} 
                showSizeChanger = {false}  
            />
        </div>
    );

}
export default CustomPagination;